      Program 	  PhaseScreen*      Implicit    none	  Integer 	  Nk,Nx,Nz,Nh,Nm,Nhm1,jskip*	  Parameter	  (Nk=4096,Nh=Nk/2,Nz=21,Nx=80,jskip=4)	  Parameter	  (Nk=8192,Nh=Nk/2,Nz=21,Nx=80,jskip=4)	  Complex     V(Nx,5,Nz),U(Nx,5,Nz),D(Nx,5,Nz),SY(Nx,5)      Real        kxvec(Nk)      Complex     drho(Nx,Nz),da(Nx,Nz),db(Nx,Nz),dzeta(Nx,Nz),dgamma(Nx,Nz)      Complex     Bp(Nk,5),Bs(Nk,5)	  Complex     Wp(Nk),Ws(Nk),Wk(Nk)	  Complex     Ea(Nk),Eb(Nk)      Real         freq,wi,rho0,rho(Nx,Nz)      Complex      alpha0,beta0      Complex      alpha(Nx,Nz),beta(Nx,Nz)      Complex      w,Ka0,Kb0,CV,Ci,C1,C0      Real         Pi,QB,rt3	  Parameter    (freq=2.0,wi=0.4,QB=50.0)      Parameter    (Pi=3.14159265358979324,rt3=1.73205080756888)      Real         kx,kxmax,dkx,intfac,dx,delz,dela      Complex      VerticalSlo,kza,kzb      Real         den0, den,Eup,Edown,Einc,kbx,kbz      Complex      ca0,cb0,cb02,ca02,b0,a0,gamma0,zeta0      Complex      ca,cb,cb2,ca2,gamma,zeta      Complex      twortqa,twortqb,w2,R1,R2,R12,Rayleigh      Complex      Rpp(Nk),Rsp(Nk),Rss(Nk)      Integer      iz,ix,ik,i,it,itmax      parameter(itmax=5)      data rho0,beta0/1.2,2.2/      w=dcmplx(2.D0*Pi*freq,wi)      type*,'w=',w      	  Ci=(0.0,1.0)	  C0=(0.0,0.0)	  C1=(1.0,0.0)	  Nm=Nk-1	  Nhm1=Nh-1	  beta0=CV(w,beta0,QB)	  alpha0=rt3*beta0      ka0=w/alpha0      kb0=w/beta0      Do 15 iz=1,nz	    Do 13 ix=1,nx          rho(ix,iz)=rho0+0.1*rho0          beta(ix,iz)=beta0+0.1*beta0          alpha(ix,iz)=rt3*beta(ix,iz)  13    continue  15  continue*	  Do 16 ix=1,nx*        rho(ix,1)=rho0*        beta(ix,1)=beta0*        alpha(ix,1)=rt3*beta0*        rho(ix,Nz)=rho0*        beta(ix,Nz)=beta0*        alpha(ix,Nz)=rt3*beta0*  16  continue	  	  ************************************************************	  kxmax=32.*Real(ka0)	  dkx=2.*kxmax/float(Nk)	  intfac=Sqrt(dkx/(2.0*Pi))	  dx=Pi/kxmax	  delz=float(jskip)*dx      kbx=Real(Kb0)*Nx*delz/(2.0*Pi)      kbz=Real(Kb0)*Nz*delz/(2.0*Pi)      type*,'kbx,kbz=',kbx,kbz      dela=delz*delz      den0=rho0	  ca0=alpha0	  cb0=beta0	  cb02=cb0*cb0	  ca02=ca0*ca0      b0=C1/(cb02*den0)      a0=C1/(ca02*den0)      gamma0=2.0*(cb02/ca02)      zeta0=4.0*den0*cb02*((cb02/ca02)-C1)      Do 19 iz=1,nz	    Do 17 ix=1,nx          den=rho(ix,iz)          ca=alpha(ix,iz)          cb=beta(ix,iz)          cb2=cb*cb          ca2=ca*ca          drho(ix,iz)=Ci*w2*dela*(den-rho0)          db(ix,iz)=Ci*dela*((C1/(cb2*den))-b0)          da(ix,iz)=Ci*dela*((C1/(ca2*den))-a0)          dgamma(ix,iz)=Ci*dela*(2.0*(cb2/ca2)-gamma0)          zeta=4.0*den*cb2*((cb2/ca2)-C1)          dzeta(ix,iz)=Ci*dela*(zeta-zeta0)  17    continue  19  continue*************************************************************	  *     FFT ordered Kx	  Do ik=1,Nhm1		Kxvec(ik+1)=float(ik)*dkx		Kxvec(ik+1+Nh)=float(ik-Nh)*dkx      Enddo	  Kxvec(1)=0.0	  Kxvec(Nh+1)=-Nh*dkx      w2=w*w	  Do ik=1,Nk	    kx=kxvec(ik)		kza=VerticalSlo(ka0,kx)		kzb=VerticalSlo(kb0,kx)		Ea(ik)=Cexp(Ci*kza*delz)		Eb(ik)=Cexp(Ci*kzb*delz)		call setB(intfac,w,kx,kza,kzb,rho0,beta0,Bp(ik,1),Bp(ik,2),     &       Bp(ik,3),Bp(ik,4),Bp(ik,5),Bs(ik,1),Bs(ik,2),Bs(ik,3),     &       Bs(ik,4),Bs(ik,5))*       set the free surface reflection array		twortqa=CSqrt(2.0*kza)		twortqb=CSqrt(2.0*kzb)	    R1=(w2 - 2*cb02*kx*kx)	    R12=R1**2	    R2=4.0*cb02*cb02*kx*kx*kza*kzb	    Rayleigh=(R12 + R2)	    Rpp(ik)=(-R12 + R2)/Rayleigh		Rsp(ik)=-4.0*cb02*cb02*kx*R1*Csqrt(kza*kzb)*     &          Cexp(0.5*Ci*(kza+kzb)*delz)/Rayleigh		Rss(ik)=Eb(ik)*Rpp(ik)		Rpp(ik)=Ea(ik)*Rpp(ik)      Enddo***************************************************************************      call setIncUp(Nk,Nx,Nz,jskip,dx,w,drho,da,db,     &     dzeta,dgamma,Bp,Bs,Wp,Ws,Wk,Ea,Eb,SY,V)	  *      call setIncDown(Nk,Nx,Nz,jskip,dx,w,drho,da,db,*     &     dzeta,dgamma,Bp,Bs,Wp,Ws,Wk,Ea,Eb,SY,V)*     Born approximation      Do iz=1,nz        Do i=1,5	    Do ix=1,nx          U(ix,i,iz)=V(ix,i,iz)        Enddo        Enddo      Enddo      Do 100 it=1,itmax        call DownUp(Nk,Nx,Nz,jskip,dx,w,drho,da,db,     &     dzeta,dgamma,Bp,Bs,Wp,Ws,Wk,Ea,Eb,SY,D,U)*       Born update        Do iz=1,nz        Do i=1,5	    Do ix=1,nx          U(ix,i,iz)=V(ix,i,iz)+U(ix,i,iz)        Enddo        Enddo        Enddo100   continue      stop 'normal completion'	  end	  COMPLEX FUNCTION VERTICALSLO(K,Kx)	  REAL Kx	  COMPLEX T,K	  T=CMPLX((K+Kx)*(K-Kx))	  VERTICALSLO=csqrt(T)	  IF(AIMAG(VERTICALSLO) .LT. 0.0)THEN 	    VERTICALSLO=-VERTICALSLO	  END IF	  RETURN	  END      SUBROUTINE FFT(CX,LX,SIGNI)      COMPLEX    CX(LX),CTEMP,CW	  Real       Pi	  Parameter (Pi=3.14159265358979324)      J=1      DO 3 I=1,LX      IF(I.GT. J) GO TO 1      CTEMP=CX(J)      CX(J)=CX(I)      CX(I)=CTEMP 1    M=LX/2 2    IF(J.LE.M) GO TO 3      J=J-M      M=M/2      IF(M.GE.1) GO TO 2 3    J=J+M      L=1 4    ISTEP=2*L      DO 5 M=1,L      AA=Pi*SIGNI*FLOAT((M-1))/FLOAT(L)      CW=CMPLX(COS(AA),SIN(AA))      DO 5 I=M,LX,ISTEP      CTEMP=CW*CX(I+L)      CX(I+L)=CX(I)-CTEMP 5    CX(I)=CX(I)+CTEMP      L=ISTEP      IF(L.LT.LX) GO TO 4      RETURN      END	        subroutine setB(intfac,w,k,kza,kzb,RHO,BETA,B11,B21,     &           B31,B41,B51,B12,B22,B32,B42,B52)**********************************************************     form the layer eigen arrays M,N*********************************************************      implicit none      real    intfac,rho,k      complex w,beta,kza,kzb,w2,twomuk	  complex B11,B21,B31,B41,B51	  complex B12,B22,B32,B42,B52	  complex ci,epsa,epsb,c1	  Ci=cmplx(0.0,1.0)	  C1=cmplx(1.0,0.0)	  w2=w*w	  twomuk=2.0*rho*beta*beta*k	  epsa=cmplx(intfac,0.0)/Csqrt(2.0*rho*w2*kza)	  epsb=cmplx(intfac,0.0)/Csqrt(2.0*rho*w2*kzb)	  B11=Ci*kza*epsa	  B12=Ci*k*epsb	  B21=Ci*k*epsa	  B22=-Ci*kzb*epsb	  B31=(twomuk*k-rho*w2)*epsa	  B32=-twomuk*kzb*epsb	  B41=-twomuk*kza*epsa	  B42=-(twomuk*k-rho*w2)*epsb	  B51=Ci*k*B21	  B52=Ci*k*B22	  return	  end      COMPLEX   FUNCTION CV(W,C0,Q0)      implicit none*     DETERMINE THE FREQUENCY DEPENDENT RECIPROCAL PROPAGATION*     VELOCITY (SLOWNESS) ACCORDING TO THE POWER LAW OF STRICK      REAL      Q0      COMPLEX   C0,W*     local variables      REAL      Pi,W0,SIGMA,T1,EPS      Complex   T,CW,temp      PARAMETER(Pi=3.14159265358979324 ,W0=1.0,SIGMA=0.10,EPS=1.E-3)      temp=CMPLX(EPS+AIMAG(W),-REAL(W))      T=CEXP(-SIGMA*CLOG(temp))*	  type*,'T=',T      T1=W0**SIGMA/SIN(SIGMA*PI/2)*	  type*,'T1=',T1      CW=(1.0,0.0)+CMPLX(0.50*T1/Q0,0.0)*T*	  type*,'CW=',CW      CV=C0/CW      RETURN      END      subroutine setdS(is,Nx,w,drho,da,db,dzeta,dgamma,Y,SY)      Implicit none *     Rd,Ru=>is=0; Td=>is=1; Tu=>is=-1      Real     dx      Integer  Nx,is      Complex  drho(Nx),da(Nx),db(Nx),dgamma(Nx),dzeta(Nx)          Complex  w,Y(Nx,5),SY(Nx,5)          Integer  ix      Complex  Ci      Ci=(0.0,1.0)      If(is.eq.0) then        Do ix=1,Nx           SY(ix,1)=SY(ix,1)+Y(ix,1)*drho(ix)		  SY(ix,2)=SY(ix,2)+Y(ix,2)*drho(ix)		  SY(ix,3)=SY(ix,3)+(Y(ix,3)*da(ix)+Y(ix,5)*dgamma(ix))		  SY(ix,4)=SY(ix,4)+Y(ix,4)*db(ix)		  SY(ix,5)=SY(ix,5)+(Y(ix,3)*dgamma(ix)+Y(ix,5)*dzeta(ix))        Enddo      else        Do ix=1,Nx           SY(ix,1)=Y(ix,1)*drho(ix)		  SY(ix,2)=Y(ix,2)*drho(ix)		  SY(ix,3)=(Y(ix,3)*da(ix)+Y(ix,5)*dgamma(ix))		  SY(ix,4)=Y(ix,4)*db(ix)		  SY(ix,5)=(Y(ix,3)*dgamma(ix)+Y(ix,5)*dzeta(ix))        Enddo      endif      return      end      subroutine setIncUp(Nk,Nx,Nz,jskip,dx,w,drho,da,db,     &          dzeta,dgamma,Bp,Bs,Wp,Ws,Wk,Ea,Eb,SY,V)      implicit none	  Integer 	  Nk,Nx,Nz,jskip	  Complex     w,V(Nx,5,Nz),SY(Nx,5)      Real        dx      Complex     drho(Nx,Nz),da(Nx,Nz),db(Nx,Nz),dzeta(Nx,Nz),dgamma(Nx,Nz)      Complex     Bp(Nk,5),Bs(Nk,5)	  Complex     Wp(Nk),Ws(Nk),Wk(Nk)	  Complex     Ea(Nk),Eb(Nk)      Integer     ik,i,j,ix,iz,izp      Real        s,inv,forw,recpu(5),recsu(5),sigpd(5),sigsd(5)      Complex     C0,C1      C0=(0.0,0.0)      C1=(1.0,0.0)	  inv=1.0	  forw=-1.0      recpu(1)=-1.0      recpu(2)=1.0      recpu(3)=1.0      recpu(4)=-1.0      recpu(5)=1.0      recsu(1)=1.0      recsu(2)=-1.0      recsu(3)=-1.0      recsu(4)=1.0      recsu(5)=-1.0      sigpd(1)=1.0      sigpd(2)=-1.0      sigpd(3)=1.0      sigpd(4)=-1.0      sigpd(5)=1.0      sigsd(1)=-1.0      sigsd(2)=1.0      sigsd(3)=-1.0      sigsd(4)=1.0      sigsd(5)=-1.0	  Do ik=1,Nk	    Wp(ik)=C0	    Ws(ik)=C0	  Enddo      Wp(Nk/2)=C1*     set normal incidence P-wavefield V, on bottom row of grid      Do i=1,5	    Do ik=1,Nk	      Wk(ik)=recpu(i)*Bp(ik,i)*Wp(ik)+recsu(i)*Bs(ik,i)*Ws(ik)	    Enddo	    call FFT(Wk,Nk,inv) !k->x	    j=1	    Do ix=1,Nx	            V(ix,i,Nz)=Wk(j)	      j=j+jskip	    Enddo      Enddo       Do 1000 iz=Nz-1,1,-1        izp=iz+1	  *	    type*,'iz=',iz*       set Tu        call setdS(-1,Nx,w,drho(1,izp),da(1,izp),db(1,izp),     &     dzeta(1,izp),dgamma(1,izp),V(1,1,izp),SY)*       Propagate upward P and SV between the screens        Do 100 i=1,5	      Do ik=1,Nk	        Wk(ik)=C0	      Enddo          j=1		  Do ix=1,Nx	        Wk(j)=SY(ix,i)	        j=j+jskip		  Enddo				  call FFT(Wk,Nk,forw) !x->k	      Do ik=1,Nk	        Wp(ik)=Wp(ik)+sigpd(i)*Bp(ik,i)*Wk(ik)	      Enddo	      Do ik=1,Nk	        Ws(ik)=Ws(ik)+sigsd(i)*Bs(ik,i)*Wk(ik)	      Enddo100     continue	    Do ik=1,Nk	      Wp(ik)=Wp(ik)*Ea(ik)	      Ws(ik)=Ws(ik)*Eb(ik)	    Enddo*     set incident P and SV field  V, on row-iz of grid      Do i=1,5	    Do ik=1,Nk	      Wk(ik)=recpu(i)*Bp(ik,i)*Wp(ik)+recsu(i)*Bs(ik,i)*Ws(ik)	    Enddo	    call FFT(Wk,Nk,inv) !k->x	    j=1	    Do ix=1,Nx	            V(ix,i,iz)=Wk(j)	      j=j+jskip	    Enddo      Enddo 1000  continue  !upward sweep      return      end      subroutine setIncDown(Nk,Nx,Nz,jskip,dx,w,drho,da,db,     &          dzeta,dgamma,Bp,Bs,Wp,Ws,Wk,Ea,Eb,SY,V)      implicit none	  Integer 	  Nk,Nx,Nz,jskip	  Complex     w,V(Nx,5,Nz),SY(Nx,5)      Real        dx      Complex     drho(Nx,Nz),da(Nx,Nz),db(Nx,Nz),dzeta(Nx,Nz),dgamma(Nx,Nz)      Complex     Bp(Nk,5),Bs(Nk,5)	  Complex     Wp(Nk),Ws(Nk),Wk(Nk)	  Complex     Ea(Nk),Eb(Nk)      Integer     ik,i,j,ix,iz,izm      Real        s,inv,forw      Real        sigpu(5),sigsu(5)      Complex     C0,C1      C0=(0.0,0.0)      C1=(1.0,0.0)	  inv=1.0	  forw=-1.0      sigpu(1)=-1.0      sigpu(2)=-1.0      sigpu(3)=1.0      sigpu(4)=1.0      sigpu(5)=1.0      sigsu(1)=-1.0      sigsu(2)=-1.0      sigsu(3)=1.0      sigsu(4)=1.0      sigsu(5)=1.0	  Do ik=1,Nk	    Wp(ik)=C0	    Ws(ik)=C0	  Enddo      Wp(1)=C1*     set normal incidence P-wavefield V, on top row of grid      Do i=1,5	    Do ik=1,Nk	      Wk(ik)=Bp(ik,i)*Wp(ik)+Bs(ik,i)*Ws(ik)	    Enddo	    call FFT(Wk,Nk,inv) !k->x	    j=1	    Do ix=1,Nx	            V(ix,i,1)=Wk(j)	      j=j+jskip	    Enddo      Enddo 	        Do 1000 iz=2,Nz        izm=iz-1	  *	    type*,'iz=',iz*       set Td        call setdS(1,Nx,w,drho(1,izm),da(1,izm),db(1,izm),     &     dzeta(1,izm),dgamma(1,izm),V(1,1,izm),SY)*       Propagate downward P and SV between the screens        Do 100 i=1,5	      Do ik=1,Nk	        Wk(ik)=C0	      Enddo          j=1		  Do ix=1,Nx	        Wk(j)=SY(ix,i)	        j=j+jskip		  Enddo				  call FFT(Wk,Nk,forw) !x->k	      Do ik=1,Nk	        Wp(ik)=Wp(ik)+sigpu(i)*Bp(ik,i)*Wk(ik)	      Enddo	      Do ik=1,Nk	        Ws(ik)=Ws(ik)+sigsu(i)*Bs(ik,i)*Wk(ik)	      Enddo100     continue	    Do ik=1,Nk	      Wp(ik)=Wp(ik)*Ea(ik)	      Ws(ik)=Ws(ik)*Eb(ik)	    Enddo*     set incident P and SV field  V, on row-iz of grid      Do i=1,5	    Do ik=1,Nk	      Wk(ik)=Bp(ik,i)*Wp(ik)+Bs(ik,i)*Ws(ik)	    Enddo	    call FFT(Wk,Nk,inv) !k->x	    j=1	    Do ix=1,Nx	            V(ix,i,iz)=Wk(j)	      j=j+jskip	    Enddo      Enddo 1000  continue  !downward sweep      return      end***************************************************************************************************************************************************************************************************************************************      subroutine DownUp(Nk,Nx,Nz,jskip,dx,w,drho,da,db,     &           dzeta,dgamma,Bp,Bs,Wp,Ws,Wk,Ea,Eb,SY,D,U)      implicit none	  Integer 	  Nk,Nx,Nz,jskip	  Complex     D(Nx,5,Nz),U(Nx,5,Nz)	  Complex     w,SY(Nx,5)      Real        dx      Complex     drho(Nx,Nz),da(Nx,Nz),db(Nx,Nz),dzeta(Nx,Nz),dgamma(Nx,Nz)      Complex     Bp(Nk,5),Bs(Nk,5)	  Complex     Wp(Nk),Ws(Nk),Wk(Nk)	  Complex     Ea(Nk),Eb(Nk)      Integer     ik,i,j,ix,iz,izp,izm      Real        s,inv,forw,recpu(5),recsu(5),sigpd(5),sigsd(5)      Real        sigpu(5),sigsu(5)      Complex     C0,C1      C0=(0.0,0.0)      C1=(1.0,0.0)	  inv=1.0	  forw=-1.0      recpu(1)=-1.0      recpu(2)=1.0      recpu(3)=1.0      recpu(4)=-1.0      recpu(5)=1.0      recsu(1)=1.0      recsu(2)=-1.0      recsu(3)=-1.0      recsu(4)=1.0      recsu(5)=-1.0      sigpd(1)=1.0      sigpd(2)=-1.0      sigpd(3)=1.0      sigpd(4)=-1.0      sigpd(5)=1.0      sigsd(1)=-1.0      sigsd(2)=1.0      sigsd(3)=-1.0      sigsd(4)=1.0      sigsd(5)=-1.0      sigpu(1)=-1.0      sigpu(2)=-1.0      sigpu(3)=1.0      sigpu(4)=1.0      sigpu(5)=1.0      sigsu(1)=-1.0      sigsu(2)=-1.0      sigsu(3)=1.0      sigsu(4)=1.0      sigsu(5)=1.0*********************************************************************     set radiation condition on top row of grid********************************************************************	  Do ik=1,Nk	    Wp(ik)=C0	    Ws(ik)=C0	  Enddo      Do i=1,5	    Do ix=1,Nx	            D(ix,i,1)=C0	    Enddo      Enddo **********************************************************************     begin downsweep*********************************************************************      Do 1000 iz=2,Nz        izm=iz-1	  *	    type*,'iz=',iz*       SY=dC(izm)*D(izm)        call setdS(1,Nx,w,drho(1,izm),da(1,izm),db(1,izm),     &       dzeta(1,izm),dgamma(1,izm),D(1,1,izm),SY)*       SY=SY+dC(izm)*U(izm)        call setdS(0,Nx,w,drho(1,izm),da(1,izm),db(1,izm),     &       dzeta(1,izm),dgamma(1,izm),U(1,1,izm),SY)*       Propagate downward P and SV between the screens        Do 100 i=1,5	      Do ik=1,Nk	        Wk(ik)=C0	      Enddo          j=1		  Do ix=1,Nx	        Wk(j)=SY(ix,i)	        j=j+jskip		  Enddo				  call FFT(Wk,Nk,forw) !x->k	      Do ik=1,Nk	        Wp(ik)=Wp(ik)+sigpu(i)*Bp(ik,i)*Wk(ik)	      Enddo	      Do ik=1,Nk	        Ws(ik)=Ws(ik)+sigsu(i)*Bs(ik,i)*Wk(ik)	      Enddo100     continue	    Do ik=1,Nk	      Wp(ik)=Wp(ik)*Ea(ik)	      Ws(ik)=Ws(ik)*Eb(ik)	    Enddo*       set incident P and SV field  U, on row-iz of grid        Do i=1,5	      Do ik=1,Nk	        Wk(ik)=Bp(ik,i)*Wp(ik)+Bs(ik,i)*Ws(ik)	      Enddo	      call FFT(Wk,Nk,inv) !k->x	      j=1	      Do ix=1,Nx	              D(ix,i,iz)=Wk(j)	        j=j+jskip	      Enddo        Enddo *********************************************************************1000  continue*     end downsweep******************************************************************************************************************************************     set radiation condition on bottom row of grid********************************************************************      Do i=1,5	    Do ix=1,Nx	            U(ix,i,Nz)=C0	    Enddo      Enddo 	  Do ik=1,Nk	    Wp(ik)=C0	    Ws(ik)=C0	  Enddo**********************************************************************     begin upsweep*********************************************************************      Do 2000 iz=Nz-1,1,-1        izp=iz+1	  *	    type*,'iz=',iz*       SY=dC(izp)*U(izp)        call setdS(-1,Nx,w,drho(1,izp),da(1,izp),db(1,izp),     &       dzeta(1,izp),dgamma(1,izp),U(1,1,izp),SY)*       SY=SY+dC(izp)*D(izp)        call setdS(0,Nx,w,drho(1,izp),da(1,izp),db(1,izp),     &       dzeta(1,izp),dgamma(1,izp),D(1,1,izp),SY)*       Propagate upward P and SV between the screens        Do 200 i=1,5	      Do ik=1,Nk	        Wk(ik)=C0	      Enddo          j=1		  Do ix=1,Nx	        Wk(j)=SY(ix,i)	        j=j+jskip		  Enddo				  call FFT(Wk,Nk,forw) !x->k	      Do ik=1,Nk	        Wp(ik)=Wp(ik)+sigpd(i)*Bp(ik,i)*Wk(ik)	      Enddo	      Do ik=1,Nk	        Ws(ik)=Ws(ik)+sigsd(i)*Bs(ik,i)*Wk(ik)	      Enddo200     continue	    Do ik=1,Nk	      Wp(ik)=Wp(ik)*Ea(ik)	      Ws(ik)=Ws(ik)*Eb(ik)	    Enddo*       set incident P and SV field  U, on row-iz of grid        Do i=1,5	      Do ik=1,Nk	        Wk(ik)=recpu(i)*Bp(ik,i)*Wp(ik)+recsu(i)*Bs(ik,i)*Ws(ik)	      Enddo	      call FFT(Wk,Nk,inv) !k->x	      j=1	      Do ix=1,Nx	              U(ix,i,iz)=Wk(j)	        j=j+jskip	      Enddo        Enddo *********************************************************************2000  continue*     end upsweep*********************************************************************      return      end